const express = require('express');
const redis = require('redis');
const client = redis.createClient();
const twilio = require('twilio');
const accountSid = 'YOUR_TWILIO_ACCOUNT_SID';
const authToken = 'YOUR_TWILIO_AUTH_TOKEN';
const clientTwilio = new twilio(accountSid, authToken);
const app = express();
const MAX_ATTEMPTS = 10;
const LOCKOUT_TIME = 10 * 60 * 1000; // 10 minutes in milliseconds

app.post('/verify', (req, res) => {
  const phoneNumber = req.body.phoneNumber; // Assuming phoneNumber is sent in the request body
  const codeEntered = req.body.code; // Assuming code entered by user is sent in the request body

  client.get(phoneNumber, (err, codeStored) => {
    if (err) {
      return res.status(500).send('Error retrieving verification code. Please try again.');
    } else if (!codeStored) {
      return res.status(400).send('Verification code expired or not found. Please request a new one.');
    } else if (codeEntered !== codeStored) {
      client.incr(phoneNumber, (err, attempts) => {
        if (attempts >= MAX_ATTEMPTS) {
          client.set(`${phoneNumber}_lockout`, 'true', 'PX', LOCKOUT_TIME);
          return res.status(401).send('Maximum attempts reached. Locked out for 10 minutes.');
        }
        return res.status(401).send('Incorrect verification code. Please try again.');
      });
    } else {
      client.del(phoneNumber);
      return res.status(200).send('Verification successful. Access granted.');
    }
  });
});

app.post('/request-code', (req, res) => {
  const phoneNumber = req.body.phoneNumber; // Assuming phoneNumber is sent in the request body
  const code = Math.floor(100000 + Math.random() * 900000); // Generate 6-digit code
  client.set(phoneNumber, code, 'EX', 600); // Store code in Redis with 10-minute expiration
  client.del(`${phoneNumber}_lockout`);
  
  clientTwilio.messages.create({
    body: `Your verification code is: ${code}`,
    to: phoneNumber,
    from: 'YOUR_TWILIO_PHONE_NUMBER'
  }).then((message) => {
    res.status(200).send('Verification code sent successfully.');
  }).catch((err) => {
    res.status(500).send('Error sending verification code. Please try again.');
  });
});

